#include <iostream>
#include <vector>
#include <cmath>
#include <thread>
#include <mutex>
#include <atomic>

using namespace std;

// Function to check if a number is prime
bool isPrime(int n) {
    if (n <= 1) return false;
    if (n <= 3) return true;
    if (n % 2 == 0 || n % 3 == 0) return false;
    for (int i = 5; i * i <= n; i += 6)
        if (n % i == 0 || n % (i + 2) == 0)
            return false;
    return true;
}

// Function to generate Fibonacci sequence up to n
vector<int> generateFibonacci(int n) {
    vector<int> fib;
    int a = 0, b = 1;
    while (a <= n) {
        fib.push_back(a);
        int temp = a;
        a = b;
        b = temp + b;
    }
    return fib;
}

